class Solution {
  public:
    int getPredecessor(Node* root, int x) {
        Node* predecessor = NULL;

        while (root) {
            if (root->val < x) {
                // Update predecessor and move to the right subtree
                predecessor = root;
                root = root->right;
            } else {
                // Move to the left subtree
                root = root->left;
            }
        }

        return predecessor == NULL ? -1: predecessor->val;
    }
};

