void inOrder(Node* root, int* nodes, int* index) {
    if (root == NULL) return;
    inOrder(root->left, nodes, index);
    nodes[(*index)++] = root->val;
    inOrder(root->right, nodes, index);
}

int getPredecessor(Node* root, int x) {
    Node* predecessor = NULL;

    while (root) {
        if (root->val < x) {
            predecessor = root;
            root = root->right;
        } else {
            root = root->left;
        }
    }

    return (predecessor == NULL) ? -1 : predecessor->val;
}

bool validateBST(Node* node, Node** prev) {
    if (node == NULL) return true;
    if (!validateBST(node->left, prev)) return false;
    if (*prev != NULL && (*prev)->val >= node->val) return false;
    *prev = node;
    return validateBST(node->right, prev);
}

